mapper.select:
SELECT exam.id AS id, exam.name AS name, cla.id AS classId, cla.class_name AS className, grade.grade_group_name AS gradeGroupName, cla.sid AS schoolYear, semester.name AS periodName, subject.subject_name AS subjectName, exam.create_time AS createTime, susr.username AS updateUser, exam.remark AS remark FROM student_exam_task exam LEFT JOIN sys_class cla ON cla.id = exam.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_semester semester ON semester.id = exam.period_id LEFT JOIN subject_rel srl ON srl.id = exam.subject_id LEFT JOIN subject ON subject.id = srl.subject_id LEFT JOIN sys_user_school_rel susr ON susr.school_id = exam.school_id AND susr.user_id = exam.update_id AND susr.deleted = 0 WHERE exam.deleted = 0
AND exam.id IN
#{item}
AND exam.school_id = #{reqModel.schoolId}
AND cla.sid = #{reqModel.schoolYear}
AND exam.period_id = #{reqModel.periodId}
AND semester.department = #{reqModel.department}
AND exam.subject_id = #{reqModel.subjectId}
AND cla.grade_group = #{reqModel.gradeId}
AND cla.id = #{reqModel.classId}
AND exam.name LIKE CONCAT('%', #{reqModel.name}, '%')
AND cla.id IN
#{item}
ORDER BY exam.id DESC

SELECT susr.username
FROM student_exam_task exam
LEFT JOIN sys_semester semester ON semester.id = exam.period_id
LEFT JOIN sys_user_school_rel susr ON susr.school_id = exam.school_id AND susr.user_id = exam.update_id AND
susr.deleted = 0
WHERE exam.deleted = 0

    AND exam.school_id = #{schoolId}


    AND semester.school_year = #{reqModel.schoolYear}


    AND exam.period_id = #{reqModel.periodId}


    AND exam.class_id = #{reqModel.classId}


    AND exam.subject_id = #{reqModel.subjectId}

ORDER BY exam.id DESC
LIMIT 1
